import pytestfrom dotenv import load_dotenvfrom ragas import SingleTurnSamplefrom ragas.metrics._answer_relevance import ResponseRelevancyfrom langchain_huggingface import HuggingFaceEmbeddingsfrom ragas.embeddings import LangchainEmbeddingsWrapperfrom llmeval.utils import get_llm_response, load_test_dataload_dotenv()filename = "tests/fixtures/responseRelevance_data.json"@pytest.mark.asyncio@pytest.mark.parametrize(    "get_data",    load_test_data(filename),    indirect=True)async def test_response_relevance(llm_wrapper, get_data):    embeddings = LangchainEmbeddingsWrapper(HuggingFaceEmbeddings())    response_relevance = ResponseRelevancy(llm=llm_wrapper, embeddings=embeddings)    relevance_score = await response_relevance.single_turn_ascore(get_data)    print("The relevance score is:", relevance_score)    assert relevance_score > 0.8@pytest.fixturedef get_data(request):    test_data = request.param    response_dict = get_llm_response(test_data)    sample = SingleTurnSample(        user_input=test_data["question"],        response=response_dict["answer"],        retrieved_contexts=[            doc["page_content"] for doc in response_dict.get("retrieved_docs")        ],        reference=test_data["reference"],    )    return sample